    public AstralPerkTreeProvider(final DataGenerator generator) {
        super(generator);
    }
    
    @Override
    public void registerPerks(final Consumer<FinishedPerk> registrar) {
        this.registerRoots(registrar);
        this.registerTravel(registrar);
        this.registerInnerRoots(registrar);
        this.registerCore(registrar);
        this.registerOuterTravel(registrar);
        this.registerRootConnectors(registrar);
        this.registerMetaPerks(registrar);
        this.registerOuterRoots(registrar);
    }
    
    private void registerOuterRoots(final Consumer<FinishedPerk> registrar) {
        this.registerAevitasOuter(registrar);
        this.registerVicioOuter(registrar);
        this.registerArmaraOuter(registrar);
        this.registerDiscidiaOuter(registrar);
        this.registerEvorsioOuter(registrar);
    }
    
